INSERT INTO spots (id, name, category, latitude, longitude, google_maps_url, quality, status, is_free, description) SELECT 'b40bf1ce-2e7e-468d-b8f1-9ff0808c9b61', '金光山厚德紫竹寺', 'carcamp', 23.030095, 120.500721, 'https://www.google.com/maps?q=23.030095,120.500721', 'new', 'published', true, '南化區縣176-2道烏山獼猴區內金光山厚德紫竹寺大廟埕隨你搭帳.前提是和廟方打個招呼告知搭營.有供三餐要告知廟方吃飯人數.搭帳用餐洗熱水澡.費用全部隨喜.真優雅清靜金速希.唯一要注意的是早上六點敲佛鐘.七點打道鼓.可帶小朋友來體驗當兵的作息時間或有賴床習慣的小朋友.家長一定要帶來此地露營幾天.保證小孩會變成每天都很早起床的~^^~' WHERE NOT EXISTS (SELECT 1 FROM spots WHERE ABS(latitude - 23.030095) < 0.0005 AND ABS(longitude - 120.500721) < 0.0005 AND category = 'carcamp');
