INSERT INTO spots (id, name, category, latitude, longitude, google_maps_url, quality, status, is_free, description) SELECT '92c74117-d989-40df-86ba-898c13454a14', '文德宮', 'carcamp', 24.042573, 120.547004, 'https://www.google.com/maps?q=24.042573,120.547004', 'new', 'published', true, '彰化花壇文德宮全省唯一官封戴烏紗冒的福正神.很靈驗的。歡迎社團好友前來參拜~重點是交通便利.環境清幽。雖道路對面有社區.但不吵雜。南面巷道也有一家小7的有厕所.但廟方亦有水厕間的.生话活機能完全，是車床族的天地。5分鐘到百年古蹟虎山嚴.10分鐘到八卦山大佛及彰化扇形古蹟車庫及各彰化小吃點。廟附近有家土雞城黑公雞口味讚.非常有名氣的。當然廟在山腳路走花秀路約25分鐘可暢遊鹿港小鎮。往南大村員林也近約' WHERE NOT EXISTS (SELECT 1 FROM spots WHERE ABS(latitude - 24.042573) < 0.0005 AND ABS(longitude - 120.547004) < 0.0005 AND category = 'carcamp');
