INSERT INTO spots (id, name, category, latitude, longitude, google_maps_url, quality, status, is_free, description) SELECT 'e3381fb1-acf5-4b34-9d3d-3353ec90fa0d', '福連國小', 'carcamp', 25.016797, 121.988721, 'https://www.google.com/maps?q=25.016797,121.988721', 'new', 'published', true, '位於新北市福隆的福連國小，後面環山前面是卯澳灣。福連國小以無敵海景出名，校內每一名小朋友畢業時都必須泳渡經過1200公尺的卯澳灣，才能從校長手裡領到畢業證書，每一位都是「水中蛟龍」相當特別。假日不時可見民眾、淺水愛好者前往戲水。這裡還有提供開放式淋浴，夏季時特別受到民眾喜愛。唯需特別注意校內露營場地沒有提供熱水、接電以及烤肉，不過無敵海景、徐徐海風就是天賜的好美優勢。' WHERE NOT EXISTS (SELECT 1 FROM spots WHERE ABS(latitude - 25.016797) < 0.0005 AND ABS(longitude - 121.988721) < 0.0005 AND category = 'carcamp');
