INSERT INTO spots (id, name, category, latitude, longitude, google_maps_url, quality, status, is_free, description) SELECT '1d36f625-0596-488f-a431-7323d9fb2823', '風力活動公園', 'carcamp', 24.850945, 120.927769, 'https://www.google.com/maps?q=24.850945,120.927769', 'new', 'published', true, '2016/12/24 謝少輔環島第六站～ 新竹風力公園～ 早上去南寮游泳池洗澡(五十塊) 洗完跑去吃早餐然後看到一隻很肥很可愛的狗 就前往風力公園了 這裡停車位很像只有假日才要收錢 但是今天是星期六... 免錢的車位很難找 廁所好像也只有公園服務區才有 而且很遠 新竹風很大 小弟幸運的找到可以擋風的地方。但是要去廁所真的是要走很長一段 剛剛吃了貢丸 嗯... 沒什麼感想 就是很貴的貢丸... 以上' WHERE NOT EXISTS (SELECT 1 FROM spots WHERE ABS(latitude - 24.850945) < 0.0005 AND ABS(longitude - 120.927769) < 0.0005 AND category = 'carcamp');
