INSERT INTO spots (id, name, category, latitude, longitude, google_maps_url, quality, status, is_free, description) SELECT '1247a42d-14cd-40f9-87ba-8165949297a2', '大崗山如意公園', 'carcamp', 22.851981, 120.335151, 'https://www.google.com/maps?q=22.851981,120.335151', 'new', 'published', true, '2017/01/15 林明賢大崗山風景區山上,因太漂亮又有無敵山海景可賞。山上平日人少還好的,假日人潮眾多在那賞夜景的。另外提供那山脚下的如意停車場,是在山脚下紅色牌樓旁的休憩區,則是安靜多的啦！~' WHERE NOT EXISTS (SELECT 1 FROM spots WHERE ABS(latitude - 22.851981) < 0.0005 AND ABS(longitude - 120.335151) < 0.0005 AND category = 'carcamp');
